import{NgModule,Component,Input,ElementRef,ContentChild,ChangeDetectionStrategy,ViewEncapsulation,ContentChildren}from"@angular/core";import{CommonModule}from"@angular/common";import{SharedModule,Header,Footer,PrimeTemplate}from"primeng/api";class Card{constructor(e){this.el=e}ngAfterContentInit(){this.templates.forEach(e=>{switch(e.getType()){case"header":this.headerTemplate=e.template;break;case"title":this.titleTemplate=e.template;break;case"subtitle":this.subtitleTemplate=e.template;break;case"content":this.contentTemplate=e.template;break;case"footer":this.footerTemplate=e.template;break;default:this.contentTemplate=e.template}})}getBlockableElement(){return this.el.nativeElement.children[0]}}Card.decorators=[{type:Component,args:[{selector:"p-card",template:`
        <div [ngClass]="'p-card p-component'" [ngStyle]="style" [class]="styleClass">
            <div class="p-card-header" *ngIf="headerFacet || headerTemplate">
                <ng-content select="p-header"></ng-content>
                <ng-container *ngTemplateOutlet="headerTemplate"></ng-container>
            </div>
            <div class="p-card-body">
                <div class="p-card-title" *ngIf="header || titleTemplate">
                    {{header}}
                    <ng-container *ngTemplateOutlet="titleTemplate"></ng-container>
                </div>
                <div class="p-card-subtitle" *ngIf="subheader || subtitleTemplate">
                    {{subheader}}
                    <ng-container *ngTemplateOutlet="subtitleTemplate"></ng-container>
                </div>
                <div class="p-card-content">
                    <ng-content></ng-content>
                    <ng-container *ngTemplateOutlet="contentTemplate"></ng-container>
                </div>
                <div class="p-card-footer" *ngIf="footerFacet || footerTemplate">
                    <ng-content select="p-footer"></ng-content>
                    <ng-container *ngTemplateOutlet="footerTemplate"></ng-container>
                </div>
            </div>
        </div>
    `,changeDetection:ChangeDetectionStrategy.OnPush,encapsulation:ViewEncapsulation.None,styles:[".p-card-header img{width:100%}"]}]}],Card.ctorParameters=()=>[{type:ElementRef}],Card.propDecorators={header:[{type:Input}],subheader:[{type:Input}],style:[{type:Input}],styleClass:[{type:Input}],headerFacet:[{type:ContentChild,args:[Header]}],footerFacet:[{type:ContentChild,args:[Footer]}],templates:[{type:ContentChildren,args:[PrimeTemplate]}]};class CardModule{}CardModule.decorators=[{type:NgModule,args:[{imports:[CommonModule],exports:[Card,SharedModule],declarations:[Card]}]}];export{Card,CardModule};